class Solution:
    def possibleStringCount(self, word: str, k: int) -> int:
        MOD = 10**9 + 7
        n = len(word)
        dp = [1] * (n + 1)
        for i in range(1, n + 1):
            if i < k:
                dp[i] = dp[i - 1]
            else:
                dp[i] = (2 * dp[i - 1] - dp[i - k]) % MOD
        return dp[n]

